    "autor": "Anónimo (Maestro de San Baudelio y colaboradores)",
    "fecha": "Hacia 1125 (siglo XII)",
    "estilo": "Románico con profunda influencia Mozárabe y Andalusí",
    "tecnica": "Pintura al fresco (fresco seco/temple sobre muro)",
