    "id": 58,
    "tituloCarta": "Isaac y Jacob",
    "autor": "Jusepe de Ribera (Lo Spagnoletto)",
    "fecha": "1637",
    "estilo": "Barroco / Naturalismo Tenebrista",
    "tecnica": "Óleo sobre lienzo",
    "dimensiones": "129 cm × 289 cm",
